2361 static Instruction *foldSelectToCopysign(SelectInst &Sel,
2362                                          InstCombiner::BuilderTy &Builder) {
2363   Value *Cond = Sel.getCondition();
2364   Value *TVal = Sel.getTrueValue();
2365   Value *FVal = Sel.getFalseValue();
2366   Type *SelType = Sel.getType();
2367 
2368   if (ICmpInst::makeCmpResultType(TVal->getType()) != Cond->getType())
2369     return nullptr;
2370 
2371   // Match select ?, TC, FC where the constants are equal but negated.
2372   // TODO: Generalize to handle a negated variable operand?
2373   const APFloat *TC, *FC;
2374   if (!match(TVal, m_APFloatAllowUndef(TC)) ||
2375       !match(FVal, m_APFloatAllowUndef(FC)) ||
2376       !abs(*TC).bitwiseIsEqual(abs(*FC)))
2377     return nullptr;
2378 
2379   assert(TC != FC && "Expected equal select arms to simplify");
2380 
2381   Value *X;
2382   const APInt *C;
2383   bool IsTrueIfSignSet;
2384   ICmpInst::Predicate Pred;
2385   if (!match(Cond, m_OneUse(m_ICmp(Pred, m_BitCast(m_Value(X)), m_APInt(C)))) ||
2386       !InstCombiner::isSignBitCheck(Pred, *C, IsTrueIfSignSet) ||
2387       X->getType() != SelType)
2388     return nullptr;
2389 
2390   // If needed, negate the value that will be the sign argument of the copysign:
2391   // (bitcast X) <  0 ? -TC :  TC --> copysign(TC,  X)
2392   // (bitcast X) <  0 ?  TC : -TC --> copysign(TC, -X)
2393   // (bitcast X) >= 0 ? -TC :  TC --> copysign(TC, -X)
2394   // (bitcast X) >= 0 ?  TC : -TC --> copysign(TC,  X)
2395   // Note: FMF from the select can not be propagated to the new instructions.
2396   if (IsTrueIfSignSet ^ TC->isNegative())
2397     X = Builder.CreateFNeg(X);
2398 
2399   // Canonicalize the magnitude argument as the positive constant since we do
2400   // not care about its sign.
2401   Value *MagArg = ConstantFP::get(SelType, abs(*TC));
2402   Function *F = Intrinsic::getDeclaration(Sel.getModule(), Intrinsic::copysign,
2403                                           Sel.getType());
2404   return CallInst::Create(F, { MagArg, X });
2405 }
