2407 Instruction *InstCombinerImpl::foldVectorSelect(SelectInst &Sel) {
2408   if (!isa<VectorType>(Sel.getType()))
2409     return nullptr;
2410 
2411   Value *Cond = Sel.getCondition();
2412   Value *TVal = Sel.getTrueValue();
2413   Value *FVal = Sel.getFalseValue();
2414   Value *C, *X, *Y;
2415 
2416   if (match(Cond, m_VecReverse(m_Value(C)))) {
2417     auto createSelReverse = [&](Value *C, Value *X, Value *Y) {
2418       Value *V = Builder.CreateSelect(C, X, Y, Sel.getName(), &Sel);
2419       if (auto *I = dyn_cast<Instruction>(V))
2420         I->copyIRFlags(&Sel);
2421       Module *M = Sel.getModule();
2422       Function *F = Intrinsic::getDeclaration(
2423           M, Intrinsic::experimental_vector_reverse, V->getType());
2424       return CallInst::Create(F, V);
2425     };
2426 
2427     if (match(TVal, m_VecReverse(m_Value(X)))) {
2428       // select rev(C), rev(X), rev(Y) --> rev(select C, X, Y)
2429       if (match(FVal, m_VecReverse(m_Value(Y))) &&
2430           (Cond->hasOneUse() || TVal->hasOneUse() || FVal->hasOneUse()))
2431         return createSelReverse(C, X, Y);
2432 
2433       // select rev(C), rev(X), FValSplat --> rev(select C, X, FValSplat)
2434       if ((Cond->hasOneUse() || TVal->hasOneUse()) && isSplatValue(FVal))
2435         return createSelReverse(C, X, FVal);
2436     }
2437     // select rev(C), TValSplat, rev(Y) --> rev(select C, TValSplat, Y)
2438     else if (isSplatValue(TVal) && match(FVal, m_VecReverse(m_Value(Y))) &&
2439              (Cond->hasOneUse() || FVal->hasOneUse()))
2440       return createSelReverse(C, TVal, Y);
2441   }
2442 
2443   auto *VecTy = dyn_cast<FixedVectorType>(Sel.getType());
2444   if (!VecTy)
2445     return nullptr;
2446 
2447   unsigned NumElts = VecTy->getNumElements();
2448   APInt PoisonElts(NumElts, 0);
2449   APInt AllOnesEltMask(APInt::getAllOnes(NumElts));
2450   if (Value *V = SimplifyDemandedVectorElts(&Sel, AllOnesEltMask, PoisonElts)) {
2451     if (V != &Sel)
2452       return replaceInstUsesWith(Sel, V);
2453     return &Sel;
2454   }
2455 
2456   // A select of a "select shuffle" with a common operand can be rearranged
2457   // to select followed by "select shuffle". Because of poison, this only works
2458   // in the case of a shuffle with no undefined mask elements.
2459   ArrayRef<int> Mask;
2460   if (match(TVal, m_OneUse(m_Shuffle(m_Value(X), m_Value(Y), m_Mask(Mask)))) &&
2461       !is_contained(Mask, PoisonMaskElem) &&
2462       cast<ShuffleVectorInst>(TVal)->isSelect()) {
2463     if (X == FVal) {
2464       // select Cond, (shuf_sel X, Y), X --> shuf_sel X, (select Cond, Y, X)
2465       Value *NewSel = Builder.CreateSelect(Cond, Y, X, "sel", &Sel);
2466       return new ShuffleVectorInst(X, NewSel, Mask);
2467     }
2468     if (Y == FVal) {
2469       // select Cond, (shuf_sel X, Y), Y --> shuf_sel (select Cond, X, Y), Y
2470       Value *NewSel = Builder.CreateSelect(Cond, X, Y, "sel", &Sel);
2471       return new ShuffleVectorInst(NewSel, Y, Mask);
2472     }
2473   }
2474   if (match(FVal, m_OneUse(m_Shuffle(m_Value(X), m_Value(Y), m_Mask(Mask)))) &&
2475       !is_contained(Mask, PoisonMaskElem) &&
2476       cast<ShuffleVectorInst>(FVal)->isSelect()) {
2477     if (X == TVal) {
2478       // select Cond, X, (shuf_sel X, Y) --> shuf_sel X, (select Cond, X, Y)
2479       Value *NewSel = Builder.CreateSelect(Cond, X, Y, "sel", &Sel);
2480       return new ShuffleVectorInst(X, NewSel, Mask);
2481     }
2482     if (Y == TVal) {
2483       // select Cond, Y, (shuf_sel X, Y) --> shuf_sel (select Cond, Y, X), Y
2484       Value *NewSel = Builder.CreateSelect(Cond, Y, X, "sel", &Sel);
2485       return new ShuffleVectorInst(NewSel, Y, Mask);
2486     }
2487   }
2488 
2489   return nullptr;
2490 }
